import { Component, ChangeDetectionStrategy, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { SheetsService } from './services/sheets.service';
import { SpeechService } from './services/speech.service';
import { GeminiService } from './services/gemini.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true,
  imports: [CommonModule],
  providers: [SheetsService, SpeechService, GeminiService],
})
export class AppComponent {
  private sheetsService = inject(SheetsService);
  private speechService = inject(SpeechService);
  private geminiService = inject(GeminiService);

  sheetUrl = signal<string>('');
  sheetData = signal<string | null>(null);
  sheetHeaders = signal<string[]>([]);
  sheetPreview = signal<string[][]>([]);

  userQuestion = signal<string | null>(null);
  aiResponse = signal<string | null>(null);

  status = signal<'idle' | 'loading_sheet' | 'listening' | 'thinking' | 'speaking' | 'error'>('idle');
  errorMessage = signal<string | null>(null);

  isSheetLoaded = signal<boolean>(false);

  constructor() {
    this.speechService.checkSupport();
  }

  onUrlInput(event: Event) {
    const input = event.target as HTMLInputElement;
    this.sheetUrl.set(input.value);
  }

  async loadSheet() {
    if (!this.sheetUrl()) return;
    this.status.set('loading_sheet');
    this.errorMessage.set(null);
    this.isSheetLoaded.set(false);
    try {
      const csvData = await this.sheetsService.loadSheetFromUrl(this.sheetUrl());
      this.sheetData.set(csvData);
      const { headers, preview } = this.sheetsService.parseCsvForPreview(csvData);
      this.sheetHeaders.set(headers);
      this.sheetPreview.set(preview);
      this.isSheetLoaded.set(true);
      this.status.set('idle');
    } catch (err) {
      console.error(err);
      this.errorMessage.set('Failed to load or parse the sheet. Please check the URL and ensure it\'s a valid, public CSV.');
      this.status.set('error');
    }
  }

  async startVoiceQuery() {
    if (!this.sheetData()) {
      this.errorMessage.set('Please load a Google Sheet first.');
      this.status.set('error');
      return;
    }

    // Reset previous query
    this.userQuestion.set(null);
    this.aiResponse.set(null);
    this.errorMessage.set(null);

    this.status.set('listening');

    try {
      const question = await this.speechService.recognizeSpeech();
      this.userQuestion.set(question);
      this.status.set('thinking');

      const responseText = await this.geminiService.askAboutData(this.sheetData()!, question);
      this.aiResponse.set(responseText);
      this.status.set('speaking');

      await this.speechService.speak(responseText);
      this.status.set('idle');

    } catch (err) {
      console.error(err);
      const message = (err instanceof Error) ? err.message : 'An unknown error occurred.';
      this.errorMessage.set(`Error during voice query: ${message}`);
      this.status.set('error');
    }
  }
}

import { Injectable } from '@angular/core';

@Injectable()
export class SheetsService {

  async loadSheetFromUrl(url: string): Promise<string> {
    if (!url || !url.startsWith('https://docs.google.com/spreadsheets/d/e/')) {
        throw new Error('Invalid Google Sheet URL. Please provide the public CSV link.');
    }
    // Simple check to ensure it's a pub?output=csv link
    if (!url.includes('pub?output=csv')) {
        // Attempt to fix common mistake of sharing the normal editor URL
        if(url.includes('/edit')) {
            throw new Error('Please publish your sheet to the web as a CSV, do not use the editor URL.');
        }
        throw new Error('URL must be a published CSV link (pub?output=csv).');
    }

    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Network response was not ok, status: ${response.status}`);
    }
    return response.text();
  }

  parseCsvForPreview(csvData: string): { headers: string[]; preview: string[][] } {
    const lines = csvData.trim().split('\n');
    if (lines.length === 0) {
      return { headers: [], preview: [] };
    }

    // Naive CSV parsing, assumes no commas within quoted strings
    const headers = lines[0].split(',');
    const preview = lines.slice(1, 6).map(line => line.split(','));

    return { headers, preview };
  }
}

import { Injectable, signal } from '@angular/core';

// This is to help with TypeScript compilation since SpeechRecognition might not be in default libs
declare var webkitSpeechRecognition: any;

@Injectable()
export class SpeechService {
  private recognition: any;
  isSupported = signal(true);

  constructor() {
    this.checkSupport();
    if(this.isSupported()) {
        const SpeechRecognition = window.SpeechRecognition || webkitSpeechRecognition;
        this.recognition = new SpeechRecognition();
        this.recognition.continuous = false;
        this.recognition.lang = 'en-US';
        this.recognition.interimResults = false;
        this.recognition.maxAlternatives = 1;
    }
  }

  checkSupport() {
      const supported = 'SpeechRecognition' in window || 'webkitSpeechRecognition' in window;
      this.isSupported.set(supported);
      if(!supported) {
          console.error('Speech recognition is not supported in this browser.');
      }
  }

  recognizeSpeech(): Promise<string> {
    if (!this.isSupported()) {
      return Promise.reject(new Error('Speech recognition not supported by your browser.'));
    }

    return new Promise((resolve, reject) => {
      this.recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        resolve(transcript);
      };

      this.recognition.onerror = (event: any) => {
        reject(new Error(event.error || 'Speech recognition failed.'));
      };

      this.recognition.onend = () => {
        // Automatically reject if it ends without a result
        // This can happen if user doesn't speak
      };

      this.recognition.start();
    });
  }

  speak(text: string): Promise<void> {
    if (!('speechSynthesis' in window)) {
      return Promise.reject(new Error('Speech synthesis not supported by your browser.'));
    }

    return new Promise((resolve, reject) => {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'en-US';
      utterance.rate = 1;
      utterance.pitch = 1;

      utterance.onend = () => {
        resolve();
      };

      utterance.onerror = (event) => {
        reject(new Error(event.error || 'Speech synthesis failed.'));
      };

      window.speechSynthesis.speak(utterance);
    });
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from '@google/genai';

@Injectable()
export class GeminiService {
  private genAI: GoogleGenAI;

  constructor() {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }
    this.genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askAboutData(data: string, question: string): Promise<string> {
    const model = 'gemini-2.5-flash';

    const prompt = `
      You are an expert data analyst.
      Analyze the following data which is in CSV format and answer the user's question.
      Be concise and clear in your response.

      Here is the CSV data:
      ---
      ${data}
      ---

      User's question: "${question}"
    `;

    try {
      const response = await this.genAI.models.generateContent({
        model: model,
        contents: prompt,
      });

      return response.text;
    } catch (error) {
      console.error('Error calling Gemini API:', error);
      throw new Error('Failed to get a response from the AI model.');
    }
  }
}

