import { Injectable } from '@angular/core';

// FIX: Use providedIn: 'root' to make this a singleton service.
@Injectable({
  providedIn: 'root'
})
export class SheetsService {

  async loadSheetFromUrl(url: string): Promise<string> {
    if (!url || !url.startsWith('https://docs.google.com/spreadsheets/d/e/')) {
        throw new Error('Invalid Google Sheet URL format. Please provide the public link from "File > Share > Publish to web".');
    }

    try {
      const urlObject = new URL(url);
      const isPublishedDoc = urlObject.pathname.includes('/pub');
      const isCsvOutput = urlObject.searchParams.get('output') === 'csv';

      if (!isPublishedDoc || !isCsvOutput) {
        if (url.includes('/edit')) {
            throw new Error('The provided URL is an editor link. Please use the "Publish to web" link instead.');
        }
        throw new Error('URL does not appear to be a published CSV link. Ensure it contains "/pub" and "output=csv".');
      }
    } catch (e) {
        // This will catch errors from `new URL()` if the URL is malformed.
        if (e instanceof Error) {
            throw e;
        }
        throw new Error('Could not parse the provided URL. Please check if it is valid.');
    }

    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Network request was not ok, status: ${response.status}`);
    }
    return response.text();
  }

  parseCsvForPreview(csvData: string): { headers: string[]; preview: string[][] } {
    const lines = csvData.trim().split('\n');
    if (lines.length === 0) {
      return { headers: [], preview: [] };
    }

    // Naive CSV parsing, but handles trimming and removing surrounding quotes from cells.
    const parseLine = (line: string) => line.split(',').map(cell => cell.trim().replace(/^"|"$/g, ''));

    const headers = parseLine(lines[0]);
    const preview = lines.slice(1, 6).map(parseLine);

    return { headers, preview };
  }
}

