}

type Status = 'idle' | 'authenticating' | 'loading_sheets' | 'loading_sheet_data' | 'listening' | 'thinking' | 'speaking' | 'error';

@Component({
  selector: 'app-full-version',
  templateUrl: './full-version.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: true,
  imports: [CommonModule],
})
export class FullVersionComponent {
  private speechService = inject(SpeechService);
  private geminiService = inject(GeminiService);
  authService = inject(GoogleAuthService);
  private apiService = inject(GoogleApiService);

  sheets = signal<Sheet[]>([]);
  selectedSheet = signal<Sheet | null>(null);
  sheetData = signal<string | null>(null);
  sheetHeaders = signal<string[]>([]);
  sheetPreview = signal<string[][]>([]);
  searchTerm = signal<string>('');

  history = signal<HistoryItem[]>([]);
  status = signal<Status>('idle');
  errorMessage = signal<string | null>(null);

  isSheetLoaded = computed(() => !!this.sheetData());

  filteredSheets = computed(() => {
    const term = this.searchTerm().toLowerCase();
    if (!term) {
      return this.sheets();
    }
    return this.sheets().filter(sheet => sheet.name.toLowerCase().includes(term));
  });

  async signIn() {
    this.status.set('authenticating');
    this.errorMessage.set(null);
    try {
      await this.authService.signIn();
      await this.loadSheets();
    } catch (err) {
      const message = err instanceof Error ? err.message : 'An unknown error occurred during sign-in.';
      this.errorMessage.set(message);
      this.status.set('error');
    }
  }

  async loadSheets() {
    this.status.set('loading_sheets');
    this.errorMessage.set(null);
    try {
      const token = this.authService.getAccessToken();
      if (!token) {
        throw new Error('Authentication token not available.');
      }
      const sheets = await this.apiService.listSheets(token);
      this.sheets.set(sheets);
      this.status.set('idle');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Could not fetch your spreadsheets.';
      this.errorMessage.set(message);
      this.status.set('error');
    }
  }

  async selectSheet(sheet: Sheet) {
    if (this.selectedSheet()?.id === sheet.id) return;

    this.selectedSheet.set(sheet);
    this.status.set('loading_sheet_data');
    this.errorMessage.set(null);
    this.sheetData.set(null);

    try {
      const token = this.authService.getAccessToken();
      if (!token) {
        throw new Error('Authentication token not available.');
      }
      const { csvData, headers, preview } = await this.apiService.getSheetData(sheet.id, token);
      this.sheetData.set(csvData);
      this.sheetHeaders.set(headers);
      this.sheetPreview.set(preview);
      this.status.set('idle');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Could not load data for the selected sheet.';
      this.errorMessage.set(message);
      this.status.set('error');
      this.selectedSheet.set(null);
    }
  }

  onSearchInput(event: Event) {
    this.searchTerm.set((event.target as HTMLInputElement).value);
  }

  async startVoiceQuery() {
    if (!this.sheetData()) {
      this.errorMessage.set('Please select and load a sheet first.');
      this.status.set('error');
      return;
    }

    this.errorMessage.set(null);
    this.status.set('listening');

    try {
      const question = await this.speechService.recognizeSpeech();
      this.status.set('thinking');

      const response: GeminiResponse = await this.geminiService.askAboutData(this.sheetData()!, question);

      const newHistoryItem: HistoryItem = {
        id: Date.now(),
        question,
        answer: response.answer,
        reasoning: response.reasoning,
      };
      this.history.update(currentHistory => [newHistoryItem, ...currentHistory]);

      this.status.set('speaking');
      await this.speechService.speak(response.answer);
      this.status.set('idle');

    } catch (err) {
      const message = (err instanceof Error) ? err.message : 'An unknown error occurred.';
      this.errorMessage.set(`Error during voice query: ${message}`);
      this.status.set('error');
    }
  }
