import { Injectable } from '@angular/core';

export interface Sheet {
  id: string;
  name: string;
  modifiedTime: string;
}

interface DriveFile {
    id: string;
    name: string;
    modifiedTime: string;
}

interface DriveFileList {
    files: DriveFile[];
}

interface SheetValues {
    values: string[][];
}


@Injectable({
  providedIn: 'root'
})
export class GoogleApiService {

  async listSheets(accessToken: string): Promise<Sheet[]> {
    const response = await fetch("https://www.googleapis.com/drive/v3/files?q=mimeType='application/vnd.google-apps.spreadsheet'&orderBy=modifiedTime desc&fields=files(id,name,modifiedTime)", {
      headers: {
        'Authorization': `Bearer ${accessToken}`
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to list Google Sheets. Status: ${response.status}`);
    }

    const data: DriveFileList = await response.json();
    return data.files || [];
  }

  async getSheetData(spreadsheetId: string, accessToken: string): Promise<{ csvData: string; headers: string[]; preview: string[][] }> {
    // We fetch only the first 1000 rows of the first sheet for performance.
    const response = await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values/A1:ZZ1000`, {
      headers: {
        'Authorization': `Bearer ${accessToken}`
      }
    });

    if (!response.ok) {
      throw new Error(`Failed to get sheet data. Status: ${response.status}`);
    }

    const data: SheetValues = await response.json();
    const rows = data.values || [];

    if (rows.length === 0) {
      return { csvData: '', headers: [], preview: [] };
    }

    const csvData = rows.map(row => row.join(',')).join('\n');
    const headers = rows[0];
    const preview = rows.slice(1, 6);

    return { csvData, headers, preview };
  }
}

import { Injectable, signal, computed } from '@angular/core';

// These interfaces are simplified versions of the Google Identity Services types.
// Using `any` or simplified types avoids needing to install large `@types/google.accounts` packages.
interface GoogleUser {
    name: string;
    email: string;
    picture: string;
}

interface TokenResponse {
    access_token: string;
    expires_in: number;
    scope: string;
}

declare global {
    const google: any;
}

@Injectable({
    providedIn: 'root'
})
export class GoogleAuthService {
    // IMPORTANT: Replace with your actual Google Cloud Client ID
    private readonly CLIENT_ID = 'YOUR_GOOGLE_CLOUD_CLIENT_ID.apps.googleusercontent.com';

    private tokenClient: any;
    private accessToken = signal<string | null>(null);
    user = signal<GoogleUser | null>(null);

    isAuthenticated = computed(() => !!this.accessToken());

    constructor() {
        this.initializeGsi();
    }

    private initializeGsi() {
        if (typeof google === 'undefined') {
            console.error('Google Identity Services script not loaded.');
            return;
        }

        google.accounts.id.initialize({
            client_id: this.CLIENT_ID,
            callback: this.handleCredentialResponse.bind(this),
        });

        this.tokenClient = google.accounts.oauth2.initTokenClient({
            client_id: this.CLIENT_ID,
            scope: 'https://www.googleapis.com/auth/drive.readonly https://www.googleapis.com/auth/spreadsheets.readonly',
            callback: this.handleTokenResponse.bind(this),
        });
    }

    private handleCredentialResponse(response: any) {
        // This function handles the response from the Sign In With Google button
        // For our purpose, we decode the JWT to get user info.
        const decodedJwt: any = JSON.parse(atob(response.credential.split('.')[1]));
        this.user.set({
            name: decodedJwt.name,
            email: decodedJwt.email,
            picture: decodedJwt.picture,
        });
    }

    private handleTokenResponse(response: TokenResponse) {
        if (response.access_token) {
            this.accessToken.set(response.access_token);
        }
    }

    signIn(): Promise<void> {
        return new Promise((resolve, reject) => {
            if (!this.tokenClient) {
                return reject(new Error('Google API client not initialized. Ensure you have added your Client ID.'));
            }

            // The 'prompt' is important. An empty prompt will skip the consent screen if already granted.
            this.tokenClient.requestAccessToken({ prompt: '' });

            // Because the callback handles success, we need a way to know if it worked.
            // We'll poll for the access token with a timeout.
            let attempts = 0;
            const interval = setInterval(() => {
                if (this.accessToken()) {
                    // Also trigger the "one-tap" sign-in to get user details
                    google.accounts.id.prompt();
                    clearInterval(interval);
                    resolve();
                } else if (attempts > 20) { // 10-second timeout
                    clearInterval(interval);
                    reject(new Error('Google Sign-In timed out. Please try again.'));
                }
                attempts++;
            }, 500);
        });
    }

    signOut() {
        this.accessToken.set(null);
        this.user.set(null);
    }

    getAccessToken(): string | null {
        return this.accessToken();
    }
}

