import { Injectable, signal } from '@angular/core';
import { Subject } from 'rxjs';

export type QueryStatus = 'idle' | 'listening' | 'thinking' | 'speaking' | 'error';

@Injectable({
  providedIn: 'root'
})
export class QueryStateService {
  isSheetLoaded = signal<boolean>(false);
  queryStatus = signal<QueryStatus>('idle');

  private startQueryAction = new Subject<void>();
  startQueryAction$ = this.startQueryAction.asObservable();

  startVoiceQuery() {
    // Only allow starting a query if the status is idle or error
    if (this.queryStatus() === 'idle' || this.queryStatus() === 'error') {
        this.startQueryAction.next();
    }
  }

  reset() {
    this.isSheetLoaded.set(false);
    this.queryStatus.set('idle');
  }
}

