import { Injectable } from '@angular/core';
import { GoogleGenAI, Type } from '@google/genai';

export interface VisualizationData {
  type: 'bar' | 'pie' | 'line';
  data: { label: string; value: number }[];
  title: string;
}

export interface GeminiResponse {
  answer: string;
  reasoning: string;
  visualization?: VisualizationData;
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private genAI: GoogleGenAI;

  constructor() {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }
    this.genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askAboutData(data: string, question: string): Promise<GeminiResponse> {
    const model = 'gemini-2.5-flash';

    const systemInstruction = `You are an expert data analyst. You will be provided with data in CSV format. Analyze the data to answer the user's question. If the user asks for a comparison, trend, or breakdown (e.g., "by category", "over time"), you MUST generate data for a visualization. Provide a direct answer, a step-by-step reasoning, and optionally, the visualization data. The visualization data should be appropriate for a bar, pie, or line chart.`;

    const contents = `CSV Data:\n---\n${data}\n---\n\nQuestion: "${question}"`;

    const responseSchema = {
      type: Type.OBJECT,
      properties: {
        answer: {
          type: Type.STRING,
          description: 'The direct and concise answer to the user\'s question based on the data.'
        },
        reasoning: {
          type: Type.STRING,
          description: 'A step-by-step explanation of how the answer was derived from the CSV data. Mention specific rows or values where applicable.'
        },
        visualization: {
          type: Type.OBJECT,
          description: 'Data for a chart visualization, if applicable to the user query.',
          properties: {
            type: {
              type: Type.STRING,
              description: 'The suggested chart type. Currently only "bar" is supported.',
              enum: ['bar']
            },
            title: {
              type: Type.STRING,
              description: 'A descriptive title for the chart.'
            },
            data: {
              type: Type.ARRAY,
              description: 'The data points for the chart.',
              items: {
                type: Type.OBJECT,
                properties: {
                  label: {
                    type: Type.STRING,
                    description: 'The label for the data point (e.g., a category on the x-axis).'
                  },
                  value: {
                    type: Type.NUMBER,
                    description: 'The numerical value for the data point (e.g., a value on the y-axis).'
                  }
                },
                required: ['label', 'value']
              }
            }
          },
          required: ['type', 'title', 'data']
        }
      },
      required: ['answer', 'reasoning']
    };

    try {
      const response = await this.genAI.models.generateContent({
        model: model,
        contents: contents,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: 'application/json',
          responseSchema: responseSchema,
        }
      });

      const responseText = response.text.trim();
      const result: GeminiResponse = JSON.parse(responseText);
      return result;

    } catch (error) {
      console.error('Error calling Gemini API:', error);
      throw new Error('Failed to get a response from the AI model.');
    }
  }
}

