import { Component, ChangeDetectionStrategy, input, ElementRef, inject, OnChanges, SimpleChanges } from '@angular/core';
import * as d3 from 'd3';

interface ChartData {
  label: string;
  value: number;
}

@Component({
  selector: 'app-chart',
  standalone: true,
  template: ``,
  styles: [`:host { display: block; width: 100%; height: 300px; }`],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ChartComponent implements OnChanges {
  chartData = input.required<ChartData[]>();

  private host = inject(ElementRef);
  private svg: any;
  private isInitialized = false;

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['chartData'] && this.chartData()) {
      if (!this.isInitialized) {
        this.createChart();
        this.isInitialized = true;
      }
      this.updateChart();
    }
  }

  private createChart(): void {
    const element = this.host.nativeElement;

    this.svg = d3.select(element)
      .append('svg')
      .attr('width', '100%')
      .attr('height', '100%')
      .attr('viewBox', `0 0 500 350`); // Use viewBox for responsiveness

    this.svg.append('g').attr('class', 'x-axis');
    this.svg.append('g').attr('class', 'y-axis');
    this.svg.append('g').attr('class', 'bars');
  }

  private updateChart(): void {
    const data = this.chartData();

    const margin = { top: 20, right: 20, bottom: 100, left: 60 };
    const width = 500 - margin.left - margin.right;
    const height = 350 - margin.top - margin.bottom;

    // X scale
    const x = d3.scaleBand()
      .domain(data.map(d => d.label))
      .range([0, width])
      .padding(0.2);

    // Y scale
    const y = d3.scaleLinear()
      .domain([0, d3.max(data, d => d.value) || 0])
      .range([height, 0]);

    // Draw X axis
    this.svg.select('.x-axis')
      .attr('transform', `translate(${margin.left}, ${height + margin.top})`)
      .call(d3.axisBottom(x))
      .selectAll('text')
      .attr('transform', 'translate(-10,0)rotate(-45)')
      .style('text-anchor', 'end')
      .style('fill', '#9ca3af');

    // Draw Y axis
    this.svg.select('.y-axis')
       .attr('transform', `translate(${margin.left}, ${margin.top})`)
      .call(d3.axisLeft(y).ticks(5))
      .selectAll('text')
      .style('fill', '#9ca3af');

    // Draw Bars
    const bars = this.svg.select('.bars')
      .attr('transform', `translate(${margin.left}, ${margin.top})`)
      .selectAll('.bar')
      .data(data);

    bars.enter()
      .append('rect')
      .attr('class', 'bar')
      .attr('x', (d: ChartData) => x(d.label)!)
      .attr('width', x.bandwidth())
      .attr('y', height) // Start from bottom for animation
      .attr('height', 0)
      .attr('fill', '#0d9488')
      .merge(bars)
      .transition()
      .duration(750)
      .attr('y', (d: ChartData) => y(d.value))
      .attr('height', (d: ChartData) => height - y(d.value));

    bars.exit().remove();
  }
}

