import { Injectable, signal } from '@angular/core';
import { Observable } from 'rxjs';

// This is to help with TypeScript compilation since SpeechRecognition might not be in default libs
declare var webkitSpeechRecognition: any;

export interface SpeechRecognitionResult {
  transcript: string;
  isFinal: boolean;
}

@Injectable({
  providedIn: 'root'
})
export class SpeechService {
  private recognition: any;
  isSupported = signal(true);

  constructor() {
    this.checkSupport();
    if (this.isSupported()) {
      const SpeechRecognition = (window as any).SpeechRecognition || webkitSpeechRecognition;
      this.recognition = new SpeechRecognition();
      this.recognition.continuous = false;
      this.recognition.lang = 'en-US';
      this.recognition.interimResults = true; // Enable interim results for live transcription
      this.recognition.maxAlternatives = 1;
    }
  }

  checkSupport() {
    const supported = 'SpeechRecognition' in window || 'webkitSpeechRecognition' in window;
    this.isSupported.set(supported);
    if (!supported) {
      console.error('Speech recognition is not supported in this browser.');
    }
  }

  recognizeSpeech$(): Observable<SpeechRecognitionResult> {
    if (!this.isSupported()) {
      return new Observable(subscriber => subscriber.error(new Error('Speech recognition not supported by your browser.')));
    }

    return new Observable(subscriber => {
      this.recognition.onresult = (event: any) => {
        let interim_transcript = '';
        let final_transcript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            final_transcript += event.results[i][0].transcript;
          } else {
            interim_transcript += event.results[i][0].transcript;
          }
        }

        if (final_transcript) {
          subscriber.next({ transcript: final_transcript, isFinal: true });
          subscriber.complete();
        } else if (interim_transcript) {
          subscriber.next({ transcript: interim_transcript, isFinal: false });
        }
      };

      this.recognition.onerror = (event: any) => {
        subscriber.error(new Error(event.error || 'Speech recognition failed.'));
      };

      this.recognition.onend = () => {
        subscriber.complete();
      };

      this.recognition.start();

      // Teardown logic
      return () => {
        this.recognition.stop();
      };
    });
  }
}

