import { Subscription } from 'rxjs';

interface HistoryItem {
  id: number;
  question: string;
  answer: string;
  reasoning: string;
  visualization?: VisualizationData;
}

const HISTORY_KEY_FREE = 'sheet_scribe_history_free';

@Component({
  selector: 'app-free-version',
