export class FreeVersionComponent implements OnInit, OnDestroy {
  private sheetsService = inject(SheetsService);
  private speechService = inject(SpeechService);
  private ttsService = inject(TtsService);
  private geminiService = inject(GeminiService);
  private queryStateService = inject(QueryStateService);

  private querySubscription: Subscription | undefined;
  private speechSubscription: Subscription | undefined;

  sheetUrl = signal<string>('');
  sheetData = signal<string | null>(null);
  sheetHeaders = signal<string[]>([]);
  sheetPreview = signal<string[][]>([]);

  history = signal<HistoryItem[]>([]);
  activeConversation = signal<HistoryItem | null>(null);
  liveTranscript = signal<string | null>(null);
  conversationTab = signal<'active' | 'history'>('active');

  status = signal<'idle' | 'loading_sheet' | 'error'>('idle');
  errorMessage = signal<string | null>(null);

  constructor() {
    effect(() => {
      this.saveHistory(this.history());
    });
  }

  ngOnInit() {
    this.history.set(this.loadHistory());

    this.querySubscription = this.queryStateService.startQueryAction$.subscribe(() => {
      if (this.sheetData()) {
        this.startVoiceQuery();
      } else {
        const message = 'Please load a sheet before asking a question.';
        this.errorMessage.set(message);
        this.queryStateService.queryStatus.set('speaking');
        this.ttsService.speak(message).then(() => {
            this.queryStateService.queryStatus.set('idle');
        });
      }
    });
  }

  ngOnDestroy() {
    this.querySubscription?.unsubscribe();
    this.speechSubscription?.unsubscribe();
  }

  private loadHistory(): HistoryItem[] {
    try {
      const data = localStorage.getItem(HISTORY_KEY_FREE);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error('Failed to load history from localStorage', e);
      return [];
    }
  }

  private saveHistory(history: HistoryItem[]) {
    localStorage.setItem(HISTORY_KEY_FREE, JSON.stringify(history));
  }

  selectConversationTab(tab: 'active' | 'history') {
    this.conversationTab.set(tab);
  }

  selectConversation(item: HistoryItem) {
    this.activeConversation.set(item);
    this.liveTranscript.set(null);
    this.conversationTab.set('active');
  }

  onUrlInput(event: Event) {
    const input = event.target as HTMLInputElement;
    this.sheetUrl.set(input.value);
  }

  async loadSheet() {
    if (!this.sheetUrl()) return;
    this.status.set('loading_sheet');
    this.errorMessage.set(null);
    this.queryStateService.isSheetLoaded.set(false);
    this.history.set([]);
    this.activeConversation.set(null);
    this.liveTranscript.set(null);
    this.conversationTab.set('active');
    try {
      const csvData = await this.sheetsService.loadSheetFromUrl(this.sheetUrl());
      this.sheetData.set(csvData);
      const { headers, preview } = this.sheetsService.parseCsvForPreview(csvData);
      this.sheetHeaders.set(headers);
      this.sheetPreview.set(preview);
      this.queryStateService.isSheetLoaded.set(true);
      this.status.set('idle');
    } catch (err) {
      console.error(err);
      const message = err instanceof Error ? err.message : 'An unknown error occurred while loading the sheet.';
      this.errorMessage.set(message);
      this.status.set('error');
      this.queryStateService.isSheetLoaded.set(false);
    }
  }

  startVoiceQuery() {
    this.errorMessage.set(null);
    this.queryStateService.queryStatus.set('listening');
    this.conversationTab.set('active');
    this.liveTranscript.set('');
    this.activeConversation.set(null);

    this.speechSubscription?.unsubscribe();

    this.speechSubscription = this.speechService.recognizeSpeech$().subscribe({
      next: (result) => {
        this.liveTranscript.set(result.transcript);
        if (result.isFinal) {
          this.handleFinalTranscript(result.transcript);
        }
      },
      error: (err) => {
        this.errorMessage.set(err.message || 'An error occurred during speech recognition.');
        this.queryStateService.queryStatus.set('error');
        this.liveTranscript.set(null);
        this.activeConversation.set(this.history()?.[0] ?? null);
      },
      complete: () => {
        if (this.queryStateService.queryStatus() === 'listening') {
          this.queryStateService.queryStatus.set('idle');
          this.liveTranscript.set(null);
          this.activeConversation.set(this.history()?.[0] ?? null);
        }
      }
    });
  }

  private async handleFinalTranscript(question: string) {
    this.liveTranscript.set(null);
    if (!question.trim()) {
      this.queryStateService.queryStatus.set('idle');
      this.activeConversation.set(this.history()?.[0] ?? null);
      return;
    }

    this.queryStateService.queryStatus.set('thinking');

    const tempHistoryItem: HistoryItem = {
      id: Date.now(),
      question,
      answer: '...',
      reasoning: '',
    };
    this.activeConversation.set(tempHistoryItem);

    try {
      const response: GeminiResponse = await this.geminiService.askAboutData(this.sheetData()!, question);

      const finalHistoryItem: HistoryItem = {
        ...tempHistoryItem,
        answer: response.answer,
        reasoning: response.reasoning,
        visualization: response.visualization,
      };

      this.history.update(currentHistory => [finalHistoryItem, ...currentHistory]);
      this.activeConversation.set(finalHistoryItem);

      this.queryStateService.queryStatus.set('speaking');
      await this.ttsService.speak(response.answer);
      this.queryStateService.queryStatus.set('idle');

    } catch (err) {
      console.error(err);
      const message = (err instanceof Error) ? err.message : 'An unknown error occurred.';
      this.errorMessage.set(`Error during voice query: ${message}`);
      this.queryStateService.queryStatus.set('error');
      this.activeConversation.set(null); // Clear broken conversation
    }
  }
}

