      this.status.set('error');
    }
  }

  async selectSheet(sheet: Sheet) {
    if (this.selectedSheet()?.id === sheet.id) return;

    this.selectedSheet.set(sheet);
    this.status.set('loading_sheet_data');
    this.errorMessage.set(null);
    this.sheetData.set(null);
    this.queryStateService.isSheetLoaded.set(false);

    // Load history for the selected sheet
    this.history.set(this.loadHistory(sheet.id));
    this.activeConversation.set(null);
    this.liveTranscript.set(null);
    this.conversationTab.set('active');

    try {
      const token = this.authService.getAccessToken();
      if (!token) {
        throw new Error('Authentication token not available.');
      }
      const { csvData, headers, preview } = await this.apiService.getSheetData(sheet.id, token);
      this.sheetData.set(csvData);
      this.sheetHeaders.set(headers);
      this.sheetPreview.set(preview);
      this.queryStateService.isSheetLoaded.set(true);
      this.status.set('idle');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Could not load data for the selected sheet.';
      this.errorMessage.set(message);
      this.status.set('error');
      this.selectedSheet.set(null);
      this.queryStateService.isSheetLoaded.set(false);
    }
  }

  onSearchInput(event: Event) {
    this.searchTerm.set((event.target as HTMLInputElement).value);
  }

  startVoiceQuery() {
    this.errorMessage.set(null);
    this.queryStateService.queryStatus.set('listening');
    this.conversationTab.set('active');
    this.liveTranscript.set('');
    this.activeConversation.set(null);

    this.speechSubscription?.unsubscribe();

    this.speechSubscription = this.speechService.recognizeSpeech$().subscribe({
      next: (result) => {
        this.liveTranscript.set(result.transcript);
        if (result.isFinal) {
          this.handleFinalTranscript(result.transcript);
        }
      },
      error: (err) => {
        this.errorMessage.set(err.message || 'An error occurred during speech recognition.');
        this.queryStateService.queryStatus.set('error');
        this.liveTranscript.set(null);
        this.activeConversation.set(this.history()?.[0] ?? null);
      },
      complete: () => {
        if (this.queryStateService.queryStatus() === 'listening') {
          this.queryStateService.queryStatus.set('idle');
          this.liveTranscript.set(null);
          this.activeConversation.set(this.history()?.[0] ?? null);
        }
      }
    });
  }

  private async handleFinalTranscript(question: string) {
    this.liveTranscript.set(null);
    if (!question.trim()) {
      this.queryStateService.queryStatus.set('idle');
      this.activeConversation.set(this.history()?.[0] ?? null);
      return;
    }

    this.queryStateService.queryStatus.set('thinking');

    const tempHistoryItem: HistoryItem = {
      id: Date.now(),
      question,
      answer: '...',
      reasoning: '',
    };
    this.activeConversation.set(tempHistoryItem);

    try {
      const response: GeminiResponse = await this.geminiService.askAboutData(this.sheetData()!, question);

      const finalHistoryItem: HistoryItem = {
        ...tempHistoryItem,
        answer: response.answer,
        reasoning: response.reasoning,
        visualization: response.visualization,
      };

      this.history.update(currentHistory => [finalHistoryItem, ...currentHistory]);
      this.activeConversation.set(finalHistoryItem);

      this.queryStateService.queryStatus.set('speaking');
      await this.ttsService.speak(response.answer);
      this.queryStateService.queryStatus.set('idle');

    } catch (err) {
      console.error(err);
      const message = (err instanceof Error) ? err.message : 'An unknown error occurred.';
      this.errorMessage.set(`Error during voice query: ${message}`);
      this.queryStateService.queryStatus.set('error');
      this.activeConversation.set(null); // Clear broken conversation
    }
  }
}

import { Injectable, signal, computed } from '@angular/core';

// These interfaces are simplified versions of the Google Identity Services types.
// Using `any` or simplified types avoids needing to install large `@types/google.accounts` packages.
interface GoogleUser {
    name: string;
    email: string;
    picture: string;
}

interface TokenResponse {
    access_token: string;
    expires_in: number;
    scope: string;
}

declare global {
    const google: any;
}

@Injectable({
    providedIn: 'root'
})
export class GoogleAuthService {
    // ===================================================================================
    // CRITICAL SETUP REQUIRED
    // ===================================================================================
    // To enable the "Full Mode" (private sheet access), you must create a Google Cloud
    // project and obtain an OAuth 2.0 Client ID.
    //
    // 1. Go to the Google Cloud Console: https://console.cloud.google.com/
    // 2. Create a new project.
    // 3. Go to "APIs & Services" > "Credentials".
    // 4. Click "+ CREATE CREDENTIALS" and choose "OAuth client ID".
    // 5. Select "Web application" as the application type.
    // 6. Under "Authorized JavaScript origins", add the URL where this app is hosted.
    //    For local development or AI Studio, you may need to add origins like
    //    `http://localhost:4200` or the specific AI Studio preview URL.
    // 7. Click "Create".
    // 8. Copy the "Client ID" that is generated and paste it below.
    //
    // NOTE: For this application to work, you also need to enable the "Google Drive API"
    // and "Google Sheets API" in your Google Cloud project's API Library.
    // ===================================================================================
    private readonly CLIENT_ID = 'REPLACE_WITH_YOUR_GOOGLE_CLOUD_CLIENT_ID.apps.googleusercontent.com';

    private tokenClient: any;
    private accessToken = signal<string | null>(null);
    user = signal<GoogleUser | null>(null);

    isAuthenticated = computed(() => !!this.accessToken());

    constructor() {
        this.initializeGsi();
    }

    private initializeGsi() {
        if (typeof google === 'undefined') {
            console.error('Google Identity Services script not loaded.');
            return;
        }

        // Do not initialize if the client ID is the placeholder
        if (this.CLIENT_ID.startsWith('REPLACE_WITH_YOUR_GOOGLE_CLOUD_CLIENT_ID')) {
            console.warn('GoogleAuthService: Placeholder Client ID is being used. Authentication will not work until it is replaced.');
            return;
        }

        google.accounts.id.initialize({
            client_id: this.CLIENT_ID,
            callback: this.handleCredentialResponse.bind(this),
        });

        this.tokenClient = google.accounts.oauth2.initTokenClient({
            client_id: this.CLIENT_ID,
            scope: 'https://www.googleapis.com/auth/drive.readonly https://www.googleapis.com/auth/spreadsheets.readonly',
            callback: this.handleTokenResponse.bind(this),
        });
    }

    private handleCredentialResponse(response: any) {
        // This function handles the response from the Sign In With Google button
        // For our purpose, we decode the JWT to get user info.
        const decodedJwt: any = JSON.parse(atob(response.credential.split('.')[1]));
        this.user.set({
            name: decodedJwt.name,
            email: decodedJwt.email,
            picture: decodedJwt.picture,
        });
    }

    private handleTokenResponse(response: TokenResponse) {
        if (response.access_token) {
            this.accessToken.set(response.access_token);
        }
    }

    signIn(): Promise<void> {
        return new Promise((resolve, reject) => {
            if (this.CLIENT_ID.startsWith('REPLACE_WITH_YOUR_GOOGLE_CLOUD_CLIENT_ID')) {
                return reject(new Error('Google Client ID is not configured. Please open `src/services/google-auth.service.ts`, follow the instructions to get a Client ID, and replace the placeholder value.'));
            }

            if (!this.tokenClient) {
                return reject(new Error('Google API client not initialized. This can happen if the Client ID is invalid or if there is a network issue.'));
            }

            // The 'prompt' is important. An empty prompt will skip the consent screen if already granted.
            this.tokenClient.requestAccessToken({ prompt: '' });

            // Because the callback handles success, we need a way to know if it worked.
            // We'll poll for the access token with a timeout.
            let attempts = 0;
            const interval = setInterval(() => {
                if (this.accessToken()) {
                    // Also trigger the "one-tap" sign-in to get user details
                    google.accounts.id.prompt();
                    clearInterval(interval);
                    resolve();
                } else if (attempts > 20) { // 10-second timeout
                    clearInterval(interval);
                    reject(new Error('Google Sign-In timed out. This may be due to a popup blocker or an invalid Client ID. Please check your browser settings and the Client ID configuration.'));
                }
                attempts++;
            }, 500);
        });
    }

    signOut() {
        this.accessToken.set(null);
        this.user.set(null);
    }

    getAccessToken(): string | null {
        return this.accessToken();
    }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI, Type } from '@google/genai';

export interface VisualizationData {
  type: 'bar' | 'pie' | 'line';
  data: { label: string; value: number }[];
  title: string;
}

export interface GeminiResponse {
  answer: string;
  reasoning: string;
  visualization?: VisualizationData;
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private genAI: GoogleGenAI;

  constructor() {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }
    this.genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askAboutData(data: string, question: string): Promise<GeminiResponse> {
    const model = 'gemini-2.5-flash';

    const systemInstruction = `You are an expert data analyst. Your primary goal is to provide clear, natural-sounding, and context-aware answers based on the provided CSV data.

RULES FOR YOUR RESPONSE:
1.  **Analyze the Data:** Carefully examine the CSV data to answer the user's question accurately.
2.  **Verbal Cadence:** Your 'answer' field will be read aloud by a text-to-speech engine. Format it for natural human speech.
    *   **Currency:** If a column header or data suggests currency (e.g., "Price", "Sales", "Revenue", "$"), verbalize the currency. Example: If the result is 75000, your answer should say "seventy-five thousand dollars."
    *   **Natural Phrasing:** Begin your answer with a conversational phrase, such as "According to the data," or "Based on my analysis,".
    *   **Dates:** If you encounter a date like '2024-01-05', phrase it naturally, like "January fifth, twenty twenty-four."
3.  **Visualizations:** If the user asks for a comparison, trend, or breakdown (e.g., "by category," "over time"), you MUST generate data for a visualization.
4.  **Structure:** Provide a direct answer in the 'answer' field, a step-by-step 'reasoning' field, and optionally, the 'visualization' data.`;

    const contents = `CSV Data:\n---\n${data}\n---\n\nQuestion: "${question}"`;

    const responseSchema = {
      type: Type.OBJECT,
      properties: {
        answer: {
          type: Type.STRING,
          description: 'The direct and concise answer to the user\'s question, formatted for natural speech as if it were being read aloud.'
        },
        reasoning: {
          type: Type.STRING,
          description: 'A step-by-step explanation of how the answer was derived from the CSV data. Mention specific rows or values where applicable.'
        },
        visualization: {
          type: Type.OBJECT,
          description: 'Data for a chart visualization, if applicable to the user query.',
          properties: {
            type: {
              type: Type.STRING,
              description: 'The suggested chart type. Currently only "bar" is supported.',
              enum: ['bar']
            },
            title: {
              type: Type.STRING,
              description: 'A descriptive title for the chart.'
            },
            data: {
              type: Type.ARRAY,
              description: 'The data points for the chart.',
              items: {
                type: Type.OBJECT,
                properties: {
                  label: {
                    type: Type.STRING,
                    description: 'The label for the data point (e.g., a category on the x-axis).'
                  },
                  value: {
                    type: Type.NUMBER,
                    description: 'The numerical value for the data point (e.g., a value on the y-axis).'
                  }
                },
                required: ['label', 'value']
              }
            }
          },
          required: ['type', 'title', 'data']
        }
      },
      required: ['answer', 'reasoning']
    };

    try {
      const response = await this.genAI.models.generateContent({
        model: model,
        contents: contents,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: 'application/json',
          responseSchema: responseSchema,
        }
      });

      const responseText = response.text.trim();
      const result: GeminiResponse = JSON.parse(responseText);
      return result;

    } catch (error) {
      console.error('Error calling Gemini API for data analysis:', error);
      throw new Error('Failed to get a response from the AI model.');
    }
  }

  async generateSpeech(text: string): Promise<string> {
    const model = 'gemini-2.5-flash-preview-tts';
    try {
      const response = await this.genAI.models.generateSpeech({
        model: model,
        contents: text,
      });

      return response.audioBytes;
    } catch (error) {
      console.error('Error calling Gemini API for TTS:', error);
      throw new Error('Failed to generate speech from the AI model.');
    }
  }
}

import { Injectable, inject } from '@angular/core';
import { GeminiService } from './gemini.service';

@Injectable({
  providedIn: 'root'
})
export class TtsService {
  private geminiService = inject(GeminiService);
  private currentAudio: HTMLAudioElement | null = null;

  async speak(text: string): Promise<void> {
    // Stop any currently playing audio
    if (this.currentAudio) {
      this.currentAudio.pause();
      this.currentAudio = null;
    }

    try {
      const audioBytes = await this.geminiService.generateSpeech(text);
      const audioSrc = `data:audio/mpeg;base64,${audioBytes}`;
      this.currentAudio = new Audio(audioSrc);

      return new Promise((resolve, reject) => {
        if (!this.currentAudio) {
            return reject(new Error('Audio object could not be created.'));
        }

        this.currentAudio.onended = () => {
          this.currentAudio = null;
          resolve();
        };

        this.currentAudio.onerror = (event) => {
          console.error('Audio playback error', event);
          this.currentAudio = null;
          reject(new Error('Failed to play the generated speech.'));
        };

        this.currentAudio.play().catch(e => {
            console.error('Error trying to play audio:', e);
            reject(e);
        });
      });
    } catch (error) {
      console.error('Error in TTS speak method:', error);
      throw error;
    }
  }
}

