  visualization?: VisualizationData;
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private genAI: GoogleGenAI;

  constructor() {
    if (!process.env.API_KEY) {
        throw new Error("API_KEY environment variable not set");
    }
    this.genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async askAboutData(data: string, question: string): Promise<GeminiResponse> {
    const model = 'gemini-2.5-flash';

    const systemInstruction = `You are an expert data analyst. Your primary goal is to provide clear, natural-sounding, and context-aware answers based on the provided CSV data.

RULES FOR YOUR RESPONSE:
1.  **Analyze the Data:** Carefully examine the CSV data to answer the user's question accurately.
2.  **Verbal Cadence:** Your 'answer' field will be read aloud by a text-to-speech engine. Format it for natural human speech.
    *   **Currency:** If a column header or data suggests currency (e.g., "Price", "Sales", "Revenue", "$"), verbalize the currency. Example: If the result is 75000, your answer should say "seventy-five thousand dollars."
    *   **Natural Phrasing:** Begin your answer with a conversational phrase, such as "According to the data," or "Based on my analysis,".
    *   **Dates:** If you encounter a date like '2024-01-05', phrase it naturally, like "January fifth, twenty twenty-four."
3.  **Visualizations:** If the user asks for a comparison, trend, or breakdown (e.g., "by category," "over time"), you MUST generate data for a visualization.
4.  **Structure:** Provide a direct answer in the 'answer' field, a step-by-step 'reasoning' field, and optionally, the 'visualization' data.`;

    const contents = `CSV Data:\n---\n${data}\n---\n\nQuestion: "${question}"`;

    const responseSchema = {
      type: Type.OBJECT,
      properties: {
        answer: {
          type: Type.STRING,
          description: 'The direct and concise answer to the user\'s question, formatted for natural speech as if it were being read aloud.'
        },
        reasoning: {
          type: Type.STRING,
          description: 'A step-by-step explanation of how the answer was derived from the CSV data. Mention specific rows or values where applicable.'
        },
        visualization: {
          type: Type.OBJECT,
          description: 'Data for a chart visualization, if applicable to the user query.',
          properties: {
            type: {
              type: Type.STRING,
              description: 'The suggested chart type. Currently only "bar" is supported.',
              enum: ['bar']
            },
            title: {
              type: Type.STRING,
              description: 'A descriptive title for the chart.'
            },
            data: {
              type: Type.ARRAY,
              description: 'The data points for the chart.',
              items: {
                type: Type.OBJECT,
                properties: {
                  label: {
                    type: Type.STRING,
                    description: 'The label for the data point (e.g., a category on the x-axis).'
                  },
                  value: {
                    type: Type.NUMBER,
                    description: 'The numerical value for the data point (e.g., a value on the y-axis).'
                  }
                },
                required: ['label', 'value']
              }
            }
          },
          required: ['type', 'title', 'data']
        }
      },
      required: ['answer', 'reasoning']
    };

    try {
      const response = await this.genAI.models.generateContent({
        model: model,
        contents: contents,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: 'application/json',
          responseSchema: responseSchema,
        }
      });

      const responseText = response.text.trim();
      const result: GeminiResponse = JSON.parse(responseText);
      return result;

    } catch (error) {
      console.error('Error calling Gemini API for data analysis:', error);
      throw new Error('Failed to get a response from the AI model.');
    }
  }
}

import { Injectable, signal } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class TtsService {
  private synth: SpeechSynthesis | undefined;
  private selectedVoice = signal<SpeechSynthesisVoice | null>(null);

  constructor() {
    if (typeof window !== 'undefined' && 'speechSynthesis' in window) {
      this.synth = window.speechSynthesis;
      // Voices often load asynchronously. We need to handle this.
      this.loadVoices();
      if (this.synth.onvoiceschanged !== undefined) {
        this.synth.onvoiceschanged = () => this.loadVoices();
      }
    } else {
      console.error('Text-to-Speech is not supported in this browser.');
    }
  }

  private loadVoices() {
    if (!this.synth) return;

    const availableVoices = this.synth.getVoices();
    if (availableVoices.length === 0) return; // Wait for the voices to be loaded

    // Heuristic to find the best available US English voice
    const bestVoice = 
      availableVoices.find(v => v.name === 'Google US English' && v.localService) ||
      availableVoices.find(v => v.lang === 'en-US' && v.localService) ||
      availableVoices.find(v => v.lang === 'en-US') ||
      availableVoices.find(v => v.lang.startsWith('en-'));

    this.selectedVoice.set(bestVoice || availableVoices[0] || null);
  }

  async speak(text: string): Promise<void> {
    return new Promise((resolve, reject) => {
      if (!this.synth || !text) {
        return reject(new Error('Speech synthesis not available or no text provided.'));
      }

      // Stop any currently speaking utterance to prevent overlap
      if (this.synth.speaking) {
        this.synth.cancel();
      }

      // Ensure voices are loaded before trying to speak
      if (this.synth.getVoices().length === 0) {
        // This is a fallback for browsers where onvoiceschanged is not reliable
        setTimeout(() => this.speak(text).then(resolve).catch(reject), 100);
        return;
      }

      const utterance = new SpeechSynthesisUtterance(text);

      utterance.onend = () => {
        resolve();
      };

      utterance.onerror = (event) => {
        console.error('SpeechSynthesisUtterance.onerror', event);
        reject(new Error(`An error occurred during speech synthesis: ${event.error}`));
      };

      if (this.selectedVoice()) {
          utterance.voice = this.selectedVoice();
      } else {
        // If our selection logic failed, try one last time to load
        this.loadVoices();
        if (this.selectedVoice()){
            utterance.voice = this.selectedVoice();
        }
      }

      this.synth.speak(utterance);
    });
  }
}

import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class TtsService {
  private audioContext: AudioContext | null = null;
  private currentSource: AudioBufferSourceNode | null = null;

  constructor() {
    // Standard AudioContext for broad browser support
    if (typeof window !== 'undefined' && (window.AudioContext || (window as any).webkitAudioContext)) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    } else {
      console.error('Web Audio API is not supported in this browser.');
    }
  }

  async speak(text: string): Promise<void> {
    if (!this.audioContext) {
      return Promise.reject(new Error('AudioContext not supported, cannot play audio.'));
    }
    if (!text) {
      return Promise.resolve(); // Nothing to speak
    }
    if (!process.env.API_KEY) {
      return Promise.reject(new Error('API_KEY environment variable not set for Text-to-Speech.'));
    }

    // Stop any currently playing audio to prevent overlap
    if (this.currentSource) {
      this.currentSource.stop();
      this.currentSource = null;
    }

    // In some browsers, the AudioContext starts in a 'suspended' state and must be resumed by a user gesture.
    // The microphone click that starts the query chain serves as this gesture.
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }

    const API_URL = `https://texttospeech.googleapis.com/v1/text:synthesize?key=${process.env.API_KEY}`;

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          input: { text: text },
          // Using a premium, studio-quality WaveNet voice for natural-sounding speech.
          voice: { languageCode: 'en-US', name: 'en-US-Studio-O' },
          audioConfig: { audioEncoding: 'MP3' },
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        console.error('Google TTS API request failed:', errorData);
        const reason = errorData?.error?.message || `Status ${response.status}`;

        // Provide a helpful, actionable error message for the most common failure case.
        if (reason.includes('API key not valid')) {
            throw new Error('Text-to-Speech API error: The provided API key is not valid for the Google Cloud Text-to-Speech API. Please ensure the API is enabled in your Google Cloud project for this key.');
        }
        throw new Error(`Text-to-Speech API error: ${reason}`);
      }

      const data = await response.json();
      if (!data.audioContent) {
        throw new Error('No audio content received from TTS API.');
      }

      // Decode the base64 audio data and play it using the Web Audio API
      const audioData = atob(data.audioContent);
      const audioBytes = new Uint8Array(audioData.length);
      for (let i = 0; i < audioData.length; i++) {
        audioBytes[i] = audioData.charCodeAt(i);
      }

      const audioBuffer = await this.audioContext.decodeAudioData(audioBytes.buffer);

      return new Promise<void>((resolve) => {
        const source = this.audioContext!.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(this.audioContext!.destination);

        source.onended = () => {
          this.currentSource = null;
          resolve();
        };

        this.currentSource = source;
        source.start(0);
      });

    } catch (error) {
      console.error('Error in TTS speak method:', error);
      // Re-throw a more generic error to be displayed in the UI
      throw new Error('Failed to generate speech from the AI model.');
    }
  }
}

import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class TtsService {
  private synth: SpeechSynthesis;
  private bestVoice: SpeechSynthesisVoice | null = null;
  private voicesLoaded: Promise<void>;

  constructor() {
    // Check for browser support
    if (typeof window !== 'undefined' && 'speechSynthesis' in window) {
      this.synth = window.speechSynthesis;
      this.voicesLoaded = new Promise(resolve => {
        // Voices often load asynchronously. We need to wait for the `onvoiceschanged` event.
        if (this.synth.getVoices().length > 0) {
          this.loadBestVoice();
          resolve();
        } else {
          this.synth.onvoiceschanged = () => {
            this.loadBestVoice();
            resolve();
          };
        }
      });
    } else {
      console.error('Speech Synthesis API is not supported in this browser.');
      // Provide a stub for unsupported environments to prevent runtime errors.
      this.synth = null!; 
      this.voicesLoaded = Promise.reject(new Error('Speech Synthesis not supported.'));
    }
  }

  private loadBestVoice(): void {
    const voices = this.synth.getVoices();
    if (!voices.length) {
      console.warn('No speech synthesis voices available.');
      return;
    }

    // Find the best quality US English voice using a priority system.
    // 1. Prioritize Google's high-quality "Google US English" voice if available on Chrome.
    // 2. Look for any other high-quality native (localService) voices.
    // 3. Fallback to the first available US English voice.
    this.bestVoice =
      voices.find(voice => voice.name === 'Google US English' && voice.lang === 'en-US') ||
      voices.find(voice => voice.lang === 'en-US' && voice.localService) ||
      voices.find(voice => voice.lang === 'en-US') ||
      voices[0]; // Ultimate fallback to the very first voice if no en-US is found

    if (this.bestVoice) {
      console.log(`TTS Service: Using voice "${this.bestVoice.name}" [${this.bestVoice.lang}]`);
    }
  }

  async speak(text: string): Promise<void> {
    if (!this.synth || !text.trim()) {
      return Promise.resolve();
    }

    // Ensure voices are loaded and the best one is selected before trying to speak.
    await this.voicesLoaded;

    // Always cancel any speech that is currently playing to prevent overlaps and glitches.
    this.synth.cancel();

    return new Promise((resolve, reject) => {
      const utterance = new SpeechSynthesisUtterance(text);

      if (this.bestVoice) {
        utterance.voice = this.bestVoice;
      }

      // Fine-tune parameters for clarity
      utterance.pitch = 1;
      utterance.rate = 1;

      utterance.onend = () => {
        resolve();
      };

      utterance.onerror = (event) => {
        console.error('SpeechSynthesisUtterance.onerror', event);
        reject(new Error(`Speech synthesis failed: ${event.error}`));
      };

      this.synth.speak(utterance);
    });
  }

  cancel(): void {
    if (this.synth) {
      this.synth.cancel();
    }
  }
}

