        throw new Error("API_KEY environment variable not set for TTS Service");
    }
    this.genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });

    if (typeof window !== 'undefined' && (window.AudioContext || (window as any).webkitAudioContext)) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    } else {
      console.error('Web Audio API is not supported in this browser.');
    }
  }

  async speak(text: string): Promise<void> {
    if (!this.audioContext) {
      return Promise.reject(new Error('AudioContext not supported, cannot play audio.'));
    }
    if (!text || !text.trim()) {
      return Promise.resolve();
    }

    // Stop any currently playing audio to prevent overlap
    this.cancel();

    // The AudioContext might start in a suspended state and needs to be resumed by a user gesture.
    // The microphone click serves as this gesture.
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }

    try {
      const response = await this.genAI.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: text
      });

      // For a TTS model, we expect audio data in the response. The SDK returns this
      // in the `parts` array with `inlineData` containing the base64-encoded audio.
      const audioPart = response.candidates?.[0]?.content?.parts?.find(part => 'inlineData' in part);

      if (!audioPart || !('inlineData' in audioPart)) {
        console.error('TTS Response did not contain audio data:', response);
        throw new Error('No audio content received from the TTS model.');
      }

      const base64Audio = audioPart.inlineData.data;

      // Decode the base64 audio and play it using the Web Audio API for high-quality playback.
      const audioData = atob(base64Audio);
      const audioBytes = new Uint8Array(audioData.length);
      for (let i = 0; i < audioData.length; i++) {
        audioBytes[i] = audioData.charCodeAt(i);
      }

      const audioBuffer = await this.audioContext.decodeAudioData(audioBytes.buffer);

      return new Promise<void>((resolve, reject) => {
        if (!this.audioContext) {
          reject(new Error("AudioContext is not available."));
          return;
        }
        const source = this.audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(this.audioContext.destination);

        source.onended = () => {
          this.currentSource = null;
          resolve();
        };

        this.currentSource = source;
        source.start(0);
      });

    } catch (error) {
      console.error('Error calling Gemini TTS model:', error);
      const message = error instanceof Error ? error.message : 'An unknown error occurred.';
      throw new Error(`Failed to generate speech from AI: ${message}`);
    }
  }

  cancel(): void {
    if (this.currentSource) {
      try {
        this.currentSource.stop();
      } catch(e) {
        // Can throw if the source is already stopped.
      }
      this.currentSource = null;
    }
  }
}

